<template>
    <v-app>
        <v-app-bar app color="primary" dark>
            <v-toolbar-title style="margin-left:16px;">CycleMagic</v-toolbar-title>
            <v-spacer></v-spacer>
            <!-- <v-btn v-on:click="test" style="margin-left:8px;" text>
                位置情報変更
            </v-btn>
            <v-btn v-on:click="getLocation" style="margin-left:8px;" text>
                位置情報取得
            </v-btn> -->
            <v-btn v-on:click="onClickStartWatching" style="margin-left:8px;" text>
                位置情報監視
            </v-btn>
        </v-app-bar>

        <v-content>
            <router-view> </router-view>
        </v-content>
    </v-app>
</template>

<script>
import getlocationCommon from "./js/GeolocationCommon";

export default {
    name: "App",
    provide: function() {
        return {
            locationProp: this.location
        };
    },
    mounted() {
        this.$router.replace({ path: "/cyclemagic/MapView" });
    },
    data: () => ({
        id: 0,
        isWatching: false,
        options: {
            enableHighAccuracy: false,
            timeout: 5000,
            maximumAge: 0
        },
        // currentLocation: {
        //     position: { lat: 35.71, lng: 139.72 },
        //     title: "現在地"
        // },
        // locationLat: 0,
        // locationLng: 0,
        // mapViewProp: {
        //     moveToLocation: null
        // }
        location: {
            position: { lat: 35.71, lng: 139.72 },
            speed: 0,
            distance: 0,
            startDate: null,
            elapsedTime: 0,
            isEnableGps: false
        },
        flg: false
    }),
    methods: {
        onClickStartWatching() {
            if (this.isWatching) {
                this.endWatching();
            } else {
                this.startWatching();
            }
            this.isWatching = !this.isWatching;
        },
        startWatching() {
            console.log("start watching");
            this.id = navigator.geolocation.watchPosition(this.updateLocation, this.failed, this.options);
            this.location.speed = 0;
            this.location.distance = 0;
            this.location.startDate = new Date();
        },
        endWatching() {
            console.log("end watching");
            // this.location.isEnableGps = false;
            navigator.geolocation.clearWatch(this.id);
        },
        updateLocation(pos) {
            console.log("update location");
            this.location.isEnableGps = true;
            // var lat = pos.coords.latitude;
            // var lng = pos.coords.longitude;
            this.setLocation(pos.coords);
            // this.moveToLocation(lat, lng);
        },
        failed(err) {
            // this.location.isEnableGps = false;
            console.warn("ERROR(" + err.code + "): " + err.message);
        },
        getLocation() {
            if (navigator.geolocation) {
                var func = this.setLocation;

                navigator.geolocation.getCurrentPosition(function(pos) {
                    func(pos.coords.latitude, pos.coords.longitude);
                });
            } else {
                console.log("error geolocation!!");
            }
        },
        setLocation(coords) {
            console.log("setCurrentLocation");
            this.location.distance += getlocationCommon.getDistance(
                this.location.position.lat,
                this.location.position.lng,
                coords.latitude,
                coords.longitude
            );
            this.location.position.lat = coords.latitude;
            this.location.position.lng = coords.longitude;
            this.location.speed = coords.speed;
            this.location.elapsedTime = (new Date().getTime() - this.location.startDate.getTime()) / 1000;
        }
    }
};
</script>
