<template>
    <div style="width:100%;height:100%;position:relative;">
        <GmapMap
            v-show="locationProp.isEnableGps"
            ref="mapRef"
            :options="{
                zoomControl: true,
                mapTypeControl: false,
                scaleControl: false,
                streetViewControl: false,
                rotateControl: false,
                fullscreenControl: false,
                disableDefaultUi: false
            }"
            :center="center"
            :zoom="zoom"
            style="position:absolute;left:0;top:0;right:0;bottom:0;"
        >
            <GmapMarker :position="locationProp.position" :clickable="true"> </GmapMarker>
            <GmapMarker v-for="(footprint, idx) of footprints" :key="idx" :position="footprint.position" :clickable="true"> </GmapMarker>
        </GmapMap>
        <div style="position:absolute;left:0;right:0;bottom:0;padding:2px">
            <v-card>
                <cycleInfo> </cycleInfo>
            </v-card>
        </div>
    </div>
</template>

<script>
import getlocationCommon from "../js/GeolocationCommon";
import cycleInfo from "./material/CycleInfo";

export default {
    data() {
        return {
            center: { lat: 35.71, lng: 139.72 },
            zoom: 14,
            lastLat: 0,
            lastLng: 0,
            isFirst: true,
            lastFootPringLat: 0,
            lastFootPringLng: 0,
            currentLat: 0,
            currentLng: 0,
            footprints: []
        };
    },
    components: {
        cycleInfo
    },
    mounted() {},
    inject: ["locationProp"],
    // provide: function() {
    //     return {
    //         locationProp: this.location
    //     };
    // },
    computed: {
        lat: function() {
            return this.locationProp.position.lat;
        },
        lng: function() {
            return this.locationProp.position.lng;
        }
    },
    watch: {
        lat: function(val) {
            this.currentLat = val;
            this.$nextTick(() => {
                this.updateLocation();
            });
        },
        lng: function(val) {
            this.currentLng = val;
            this.$nextTick(() => {
                this.updateLocation();
            });
        }
    },
    methods: {
        updateLocation() {
            if (this.lastLat == this.currentLat && this.lastLng == this.currentLng) {
                console.log("already location");
                return;
            }
            console.log("updateLocation");

            this.lastLat = this.currentLat;
            this.lastLng = this.currentLng;

            if (this.isFirst) {
                this.isFirst = !this.isFirst;
                this.addFootPrint();
            } else {
                var dist = getlocationCommon.getDistance(this.lastFootPringLat, this.lastFootPringLng, this.currentLat, this.currentLng);
                if (dist * 1000 > 10) {
                    this.addFootPrint();
                }
            }

            this.$refs.mapRef.$mapPromise.then(map => {
                console.log("move");
                map.panTo({ lat: this.currentLat, lng: this.currentLng });
            });
        },
        addFootPrint(lat, lng) {
            this.lastFootPringLat = this.currentLat;
            this.lastFootPringLng = this.currentLng;
            this.footprints.push({
                position: {
                    lat: this.lastFootPringLat,
                    lng: this.lastFootPringLng
                }
            });
        }
    }
};
</script>
